// 极简版认证路由 - 修复版：持久化用户到 data/users.json + PostgreSQL 双写
import express from 'express';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, '../..');
const DATA_DIR = path.join(PROJECT_ROOT, 'data');
const USERS_FILE = path.join(DATA_DIR, 'users.json');

// 确保数据目录和文件存在
if (!fs.existsSync(DATA_DIR)) {
  fs.mkdirSync(DATA_DIR, { recursive: true });
}
if (!fs.existsSync(USERS_FILE)) {
  fs.writeFileSync(USERS_FILE, JSON.stringify([]));
}

// JWT密钥 - 必须与 middleware/auth.js 一致
const JWT_SECRET = process.env.JWT_SECRET || 'claw-default-secret-key-for-development-only-32chars';

// PostgreSQL pool（延迟加载，避免启动错误）
let _pool = null;
async function getPool() {
  if (_pool) return _pool;
  try {
    const pg = await import('pg');
    const { Pool } = pg.default || pg;
    _pool = new Pool({
      connectionString: process.env.DATABASE_URL,
      ssl: { rejectUnauthorized: false },
    });
    return _pool;
  } catch {
    return null;
  }
}

// 初始化 payment 所需表（延迟自动执行）
let _tablesInitialized = false;
async function ensurePaymentTables() {
  if (_tablesInitialized) return;
  _tablesInitialized = true;
  const pool = await getPool();
  if (!pool) return;
  try {
    // shouqianba_terminals 表
    await pool.query(`
      CREATE TABLE IF NOT EXISTS shouqianba_terminals (
        id SERIAL PRIMARY KEY,
        terminal_sn VARCHAR(50) UNIQUE,
        terminal_key VARCHAR(100),
        device_id VARCHAR(100),
        status VARCHAR(20) DEFAULT 'active',
        last_checkin_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
      )
    `);
    // 创建测试终端（如果没有）
    const termResult = await pool.query("SELECT COUNT(*) FROM shouqianba_terminals WHERE status = 'active'");
    if (parseInt(termResult.rows[0].count) === 0) {
      await pool.query(`
        INSERT INTO shouqianba_terminals (terminal_sn, terminal_key, device_id, status)
        VALUES ('91803325', '677da351628d3fe7664321669c3439b2', 'DEV-TEST-001', 'active')
        ON CONFLICT (terminal_sn) DO NOTHING
      `);
      console.log('[认证] 测试收钱吧终端已创建');
    }
    console.log('[认证] Terminal 表初始化完成');
  } catch (err) {
    console.error('[认证] Terminal 表初始化失败:', err.message);
  }
}

// PostgreSQL 优先查找用户
async function findUserByEmailPG(email) {
  const pool = await getPool();
  if (!pool) return null;
  try {
    const result = await pool.query(
      'SELECT id::text, email, password, name, membership_type, created_at FROM users WHERE email = $1',
      [email]
    );
    if (result.rows[0]) {
      return {
        id: result.rows[0].id,
        email: result.rows[0].email,
        name: result.rows[0].name,
        plan: result.rows[0].membership_type || 'free',
        hashedPassword: result.rows[0].password, // PostgreSQL 存的是加密密码
        createdAt: result.rows[0].created_at
      };
    }
  } catch (err) {
    console.error('[认证] PostgreSQL 查询失败:', err.message);
  }
  return null;
}

// JSON 文件操作（降级方案）
function getUsers() {
  try {
    return JSON.parse(fs.readFileSync(USERS_FILE, 'utf8'));
  } catch {
    return [];
  }
}

function saveUsers(users) {
  try {
    fs.writeFileSync(USERS_FILE, JSON.stringify(users, null, 2));
    return true;
  } catch (err) {
    console.error('保存用户失败:', err);
    return false;
  }
}

function findUserByEmailJSON(email) {
  return getUsers().find(u => u.email === email);
}

function findUserById(id) {
  return getUsers().find(u => u.id === id);
}

function createUser(user) {
  const users = getUsers();
  users.push(user);
  return saveUsers(users) ? user : null;
}

// 同步用户到 PostgreSQL（异步，不阻塞）
async function syncUserToPostgres(user) {
  const pool = await getPool();
  if (!pool) return;
  try {
    // 尝试更新已有记录（包含加密密码）
    const upd = await pool.query(
      'UPDATE users SET name=$1, membership_type=$2, password=$3, updated_at=NOW() WHERE email=$4 RETURNING id',
      [user.name, user.plan || 'free', user.password || null, user.email]
    );
    if (upd.rowCount === 0) {
      // 用户不存在，插入新记录
      await pool.query(
        'INSERT INTO users (email, name, membership_type, password) VALUES ($1,$2,$3,$4) ON CONFLICT (email) DO NOTHING',
        [user.email, user.name, user.plan || 'free', user.password || null]
      );
    }
    // 确保 quotas 记录存在
    await pool.query(
      `INSERT INTO quotas (user_id, text_limit, text_generations, image_limit, image_generations, products_limit)
       VALUES ($1,50,0,20,0,100)
       ON CONFLICT (user_id) DO NOTHING`,
      [user.id]
    );
  } catch (err) {
    console.error(`[认证] PostgreSQL同步失败 (${user.email}):`, err.message);
  }
}

// 生成唯一用户ID
function generateUserId() {
  return 'id_' + Date.now().toString(36) + '_' + Math.random().toString(36).substring(2, 9);
}

// 预定义内置账号（仅用于兼容，不持久化）
const BUILTIN_USERS = {
  'admin@claw.com': { id: 'user-admin-001', name: '管理员', role: 'admin', plan: 'enterprise' },
  'user@claw.com': { id: 'user-demo-001', name: '演示用户', role: 'user', plan: 'premium' },
  'test@claw.com': { id: 'user-test-001', name: '测试用户', role: 'user', plan: 'basic' }
};

const router = express.Router();

// POST /api/auth/login
router.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;
    if (!email || !password) {
      return res.status(400).json({ success: false, error: '邮箱和密码不能为空' });
    }

    console.log(`[认证] 登录: ${email}`);
    
    // 优先从 PostgreSQL 读取用户
    let user = await findUserByEmailPG(email);
    
    // 如果 PG 没有，尝试 JSON 文件
    if (!user) {
      user = findUserByEmailJSON(email);
    }
    
    // 内置账号兼容
    if (!user && BUILTIN_USERS[email]) {
      user = { ...BUILTIN_USERS[email], email };
    }

    if (!user) {
      return res.status(401).json({ success: false, error: '用户不存在' });
    }

    // 密码验证（bcrypt 加密优先，兼容旧明文密码）
    if (user.hashedPassword) {
      // 加密密码：bcrypt 验证
      const valid = await bcrypt.compare(password, user.hashedPassword);
      if (!valid) {
        return res.status(401).json({ success: false, error: '密码错误' });
      }
    } else if (user.password) {
      // 旧明文密码：直接比对
      if (user.password !== password) {
        return res.status(401).json({ success: false, error: '密码错误' });
      }
    } else {
      return res.status(401).json({ success: false, error: '密码错误' });
    }

    const token = jwt.sign(
      { userId: user.id, email: user.email, role: user.role || 'user' },
      JWT_SECRET, { expiresIn: '7d' }
    );

    res.status(200).json({
      success: true, message: '登录成功',
      data: { user: { id: user.id, email: user.email, name: user.name, role: user.role || 'user', plan: user.plan || 'free' }, token }
    });
  } catch (error) {
    console.error('[认证] 登录错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// POST /api/auth/register
router.post('/register', async (req, res) => {
  try {
    const { email, password, name } = req.body;
    if (!email || !password) {
      return res.status(400).json({ success: false, error: '邮箱和密码不能为空' });
    }

    console.log(`[认证] 注册: ${email}`);
    if (findUserByEmailJSON(email) || BUILTIN_USERS[email]) {
      return res.status(400).json({ success: false, error: '该邮箱已被注册' });
    }

    // 密码加密存储
    const hashedPassword = await bcrypt.hash(password, 12);

    const userId = generateUserId();
    const user = {
      id: userId, email, name: name || email.split('@')[0],
      role: 'user', plan: 'free',
      hashedPassword, // 加密后的密码
      createdAt: new Date().toISOString()
    };
    if (!createUser(user)) {
      return res.status(500).json({ success: false, error: '用户创建失败' });
    }

    // 异步同步到 PostgreSQL（包含加密密码）
    syncUserToPostgres({ ...user, password: hashedPassword }).catch(() => {});

    const token = jwt.sign(
      { userId, email, role: 'user' },
      JWT_SECRET, { expiresIn: '7d' }
    );

    res.status(201).json({
      success: true,
      data: { user: { id: userId, email, name: user.name, role: 'user', plan: 'free' }, token }
    });
  } catch (error) {
    console.error('[认证] 注册错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// GET /api/auth/profile
router.get('/profile', (req, res) => {
  try {
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({ success: false, error: '未提供认证令牌' });
    }
    const token = authHeader.substring(7);
    try {
      const decoded = jwt.verify(token, JWT_SECRET);
      const user = findUserById(decoded.userId);
      if (user) {
        return res.json({ success: true, data: { user: { ...user, email: decoded.email } } });
      }
      if (BUILTIN_USERS[decoded.email]) {
        return res.json({ success: true, data: { user: { ...BUILTIN_USERS[decoded.email], email: decoded.email } } });
      }
      return res.status(401).json({ success: false, error: '用户不存在' });
    } catch {
      return res.status(401).json({ success: false, error: '无效的令牌' });
    }
  } catch (error) {
    console.error('[认证] 获取个人资料错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// GET /api/auth/test
router.get('/test', async (req, res) => {
  // 首次访问时确保表已创建
  await ensurePaymentTables();
  res.json({
    success: true,
    data: {
      service: 'claw-auth', version: '1.0.2-fixed',
      status: 'active', mode: 'JSON+PG双写认证',
      endpoints: ['POST /login', 'POST /register', 'GET /profile']
    }
  });
});

export default router;
